        guard let pe = partialComplex.partialEntityInstance(eSOLID_WITH_DEPRESSION.PartialEntity.self) else { return }

        if pe._depth == nil, self._depth__provider(complex: partialComplex) == nil, 
          let base__depth__provider = self._depth__provider(complex: baseComplex) {
          pe._depth = base__depth__provider._depth__getter(complex: baseComplex)
        }
      }
      public override var typeMembers: Set<SDAI.STRING> {
        var members = Set<SDAI.STRING>()
        members.insert(SDAI.STRING(Self.typeName))
        return members
      }


      //VALUE COMPARISON SUPPORT
      public override func hashAsValue(into hasher: inout Hasher, visited complexEntities: inout Set<SDAI.ComplexEntity>) {
        super.hashAsValue(into: &hasher, visited: &complexEntities)
        self._depth?.value.hashAsValue(into: &hasher, visited: &complexEntities)
      }

      public override func isValueEqual(to rhs: SDAI.PartialEntity, visited comppairs: inout Set<SDAI.ComplexPair>) -> Bool {
        guard let rhs = rhs as? Self else { return false }
        if !super.isValueEqual(to: rhs, visited: &comppairs) { return false }
        if let comp = self._depth?.value.isValueEqualOptionally(to: rhs._depth?.value, visited: &comppairs)	{
          if !comp { return false }
        }
        else { return false }
        return true
      }

      public override func isValueEqualOptionally(to rhs: SDAI.PartialEntity, visited comppairs: inout Set<SDAI.ComplexPair>) -> Bool? {
        guard let rhs = rhs as? Self else { return false }
        var result: Bool? = true
        if let comp = super.isValueEqualOptionally(to: rhs, visited: &comppairs) {
          if !comp { return false }
        }
        else { result = nil }
        if let comp = self._depth?.value.isValueEqualOptionally(to: rhs._depth?.value, visited: &comppairs) {
          if !comp { return false }
        }
        else { result = nil }
        return result
      }


      //EXPRESS IMPLICIT PARTIAL ENTITY CONSTRUCTOR
      /// initialize from explicit attribute values
      public init(DEPTH: tPOSITIVE_LENGTH_MEASURE? ) {

        self._depth = DEPTH

        super.init(asAbstractSuperclass:())
      }

      //PARTIAL ENTITY COPY CONSTRUCTOR
      /// copy constructor
      public required convenience init(from original:SDAI.PartialEntity) {
        let original = original as! Self
        self.init( DEPTH: original._depth )
      }

      //p21 PARTIAL ENTITY CONSTRUCTOR
      /// initialize from ISO 10303-21 exchange structure parameters
      public required convenience init?(
        parameters: [P21Decode.ExchangeStructure.Parameter],
        exchangeStructure: P21Decode.ExchangeStructure
      ) {
        let numParams = 1
        guard parameters.count == numParams
        else { exchangeStructure.error = "number of p21 parameters(\(parameters.count)) are different from expected(\(numParams)) for partial entity(\(Self.entityName)) constructor"; return nil }

        guard case .success(let p0) = exchangeStructure.recoverOmittableParameter(as: 
          tPOSITIVE_LENGTH_MEASURE.self, from: parameters[0])
        else { exchangeStructure.add(errorContext: "while recovering parameter [0]DEPTH for partial entity(\(Self.entityName)) constructor"); return nil }

        self.init( DEPTH: p0 )
      }
    }
  }
}

//MARK: - Entity Dynamic Attribute Protocols
internal protocol eSOLID_WITH_DEPRESSION__DEPTH__provider {
  @_documentation(visibility:public)
  func _depth__getter(complex: SDAI.ComplexEntity) -> 
    AP242_MANAGED_MODEL_BASED_3D_ENGINEERING_MIM_LF.tPOSITIVE_LENGTH_MEASURE
}
